output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(COUNT(*) AS ?count) WHERE {
  VALUES ?club {
    wd:Q2521385 wd:Q249679
  }
  ?grand_final a wd:Q4940783 ; wdt:P4110 ?club ; wdt:P1352 2 .
  ?grand_final wdt:P157 ?season .
  ?season wdt:P157 ?competition .
  FILTER(?competition = wd:Q388556 || ?competition = wd:Q5420)
}

